local LxBaseHandler = require("LApp.handler.LxBaseHandler")
---@class LxMemoryStoreHandler:LxBaseHandler
local LxMemoryStoreHandler = classX("LxMemoryStoreHandler", LxBaseHandler)

function LxMemoryStoreHandler:Initialize()
    LxBaseHandler.Initialize(self)
end

function LxMemoryStoreHandler:Dispose()
    LxBaseHandler.Dispose(self)
end

function LxMemoryStoreHandler:ClearHandler()
    LxBaseHandler.ClearHandler(self)
end

function LxMemoryStoreHandler:InitOk()
end

-- 完成登录后
function LxMemoryStoreHandler:LoginOk()
    self:MemoryStoreInfoReq()
end

function LxMemoryStoreHandler:InitHandler()
     self:AddMsgHandler(LxProtoIds.MemoryStoreInfoResp, self.OnMemoryStoreInfoResp, self)
     self:AddMsgHandler(LxProtoIds.MemoryShardActiveResp, self.OnMemoryShardActiveResp, self)
     self:AddMsgHandler(LxProtoIds.MemoryAttrRewardResp, self.OnMemoryAttrRewardResp, self)
end

----------------------------------------------
--- c2s

--- 获取记忆仓库数据
function LxMemoryStoreHandler:MemoryStoreInfoReq()
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MemoryStoreInfoReq)
    SendMessage(LxProtoIds.MemoryStoreInfoReq, proto)
end

--- 激活记忆碎片
---@field cardRefId @记忆卡片配置ID
function LxMemoryStoreHandler:MemoryShardActiveReq(cardRefId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MemoryShardActiveReq)
    proto.cardRefId = cardRefId
    SendMessage(LxProtoIds.MemoryShardActiveReq, proto)
end

--- 领取卡片属性奖励
---@field cardRefId @记忆卡片配置ID
function LxMemoryStoreHandler:MemoryAttrRewardReq(cardRefId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MemoryAttrRewardReq)
    proto.cardRefId = cardRefId
    SendMessage(LxProtoIds.MemoryAttrRewardReq, proto)
end

----------------------------------------------
--- s2c

--- 获取记忆仓库数据
function LxMemoryStoreHandler:OnMemoryStoreInfoResp(pb)
    --- 已激活的记忆卡列表
    ModuleCenter.MemoryStore:SetPbMemoryCards(pb.cards)
    CtrlCenter.Instance:RefreshMainCityRP()
end

--- 激活记忆碎片
function LxMemoryStoreHandler:OnMemoryShardActiveResp(pb)
    ModuleCenter.MemoryStore:SetPbMemoryCardShardRefId(pb)
    FireEvent(EventNames.REFRESH_MEMORYSTORE)
    FireEvent(EventNames.RP_MEMORY_CHANG)
    CtrlCenter.Instance:RefreshMainCityRP()
end

--- 领取卡片属性奖励
function LxMemoryStoreHandler:OnMemoryAttrRewardResp(pb)
    ModuleCenter.MemoryStore:SetPbMemoryCardTakeReward(pb.cardRefId,pb.takeAttr)

    --TODO 飘奖励
    --- 获得奖励
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.MemoryAttrReward, pb.rewardInfo)
    FireEvent(EventNames.REFRESH_MEMORYSTORE)
    FireEvent(EventNames.RP_MEMORY_CHANG)
    CtrlCenter.Instance:RefreshMainCityRP()
end

return LxMemoryStoreHandler